    Args:
        query: The user's query string.

    Returns:
        str: The stringified result of the evaluation, or 'Error!' on error/danger.
    """
    qlog = _truncate_for_log(query if isinstance(query, str) else repr(query))
    logger.info("Evaluating user query: query=%r", qlog)
    try:
        tree = _parse_query(query)
        result = _evaluate_query_ast(tree)
        rlog = _truncate_for_log(result)
        logger.info("Query evaluation succeeded: query=%r result=%r", qlog, rlog)
        return result
    except Exception as e:
        elog = _truncate_for_log(str(e))
        logger.warning(
            "Query evaluation failed: query=%r error=%s message=%r",
            qlog,
            e.__class__.__name__,
            elog,
        )
        return 'Error!'


